**Analysis:**

- Sharpe: 0.34 (need 0.8+) ❌
- Drawdown: 11.4% ✓
- Consistency: 75% ✓
- Trades: 144 ✓
- Win rate / profit factor both 0.0 → metric calculation issue, but real problem is mean return 8% vs 14.86% benchmark

**Root cause:** Dual filter (positive VAA score AND above 200d SMA) is chronically over-filtering equity exposure. The SMA filter added on top of the positive-score filter creates compounding conservatism. Also: falling back to only 1 safe asset when neither filter passes means too much time parked in bonds.

**Fix:** Switch to pure VAA breadth-ratio allocation — the academically-proven approach with documented Sharpe 1.0-1.4. Breadth fraction directly scales equity vs defensive split. No dual gate. Allocate to top-3 positive aggressive assets + best defensive asset proportionally. Keep vol targeting.

```json
{
  "action": "submit_and_backtest",
  "strategy": {
    "name": "VAA Breadth Ratio Momentum",
    "strategy_code": "import pandas as pd
import numpy as np
from app.strategy.base import BaseStrategy


class VAABreadthRatio(BaseStrategy):
    name = 'VAA Breadth Ratio Momentum'
    multi_asset = True

    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.params = {
            'rebalance_period': 21,
            'vol_lookback': 21,
            'vol_target': 0.20,
            'max_scale': 2.0,
            'total_size': 0.95,
            'top_n_equity': 3,
        }

    def generate_signals(self, data):
        syms = list(data.keys())
        dates = data[syms[0]].index
        n = len(dates)

        aggressive = [s for s in ['SPY', 'QQQ', 'IWM', 'VTI', 'EFA'] if s in data]
        defensive = [s for s in ['TLT', 'AGG', 'GLD'] if s in data]
        universe = aggressive + defensive

        closes = {s: data[s]['close'].values.astype(float) for s in syms}

        sig_arr = {s: np.zeros(n, dtype=int) for s in syms}
        sz_arr = {s: np.zeros(n, dtype=float) for s in syms}

        p = self.params
        warmup = 260
        last_reb = -p['rebalance_period']
        cur_alloc = {s: 0.0 for s in syms}

        def vaa_score(s, idx):
            if s not in closes or idx < 252:
                return None
            c = closes[s]
            score = 0.0
            for period, w in [(21, 12), (63, 4), (126, 2), (252, 1)]:
                if idx >= period and c[idx - period] > 0:
                    score += w * (c[idx] / c[idx - period] - 1.0)
            return score

        def get_vol(s, idx):
            lb = p['vol_lookback']
            if idx < lb + 1 or s not in closes:
                return 0.15
            px = closes[s][idx - lb:idx + 1]
            rets = np.diff(np.log(np.maximum(px, 1e-10)))
            return max(np.std(rets) * np.sqrt(252), 0.04)

        def inv_vol_weights(asset_list, idx):
            if not asset_list:
                return {}
            vols = {s: get_vol(s, idx) for s in asset_list}
            inv = {s: 1.0 / v for s, v in vols.items()}
            total = sum(inv.values())
            if total <= 0:
                return {s: 1.0 / len(asset_list) for s in asset_list}
            return {s: iv / total for s, iv in inv.items()}

        for i in range(warmup, n):
            if (i - last_reb) < p['rebalance_period']:
                for s in syms:
                    a = cur_alloc.get(s, 0.0)
                    if a > 0.0:
                        sig_arr[s][i] = 1
                        sz_arr[s][i] = a
                continue

            last_reb = i
            cur_alloc = {s: 0.0 for s in syms}
            date = dates[i]

            scores = {}
            for s in universe:
                sc = vaa_score(s, i)
                if sc is not None:
                    scores[s] = sc

            if not scores:
                continue

            # Breadth: fraction of aggressive assets with positive VAA score
            scored_aggressive = [s for s in aggressive if s in scores]
            if not scored_aggressive:
                continue

            pos_aggressive = [s for s in scored_aggressive if scores[s] > 0]
            breadth = len(pos_aggressive) / len(scored_aggressive)

            # Equity fraction proportional to breadth
            equity_frac = breadth
            safe_frac = 1.0 - equity_frac

            weights = {}

            # Equity portion: top N positive aggressive assets by score, inv-vol weighted
            if equity_frac > 0 and pos_aggressive:
                top_eq = sorted(pos_aggressive, key=lambda s: scores[s], reverse=True)[:p['top_n_equity']]
                eq_w = inv_vol_weights(top_eq, i)
                for s, w in eq_w.items():
                    weights[s] = weights.get(s, 0.0) + w * equity_frac

            # Safe portion: top defensive assets by score, inv-vol weighted
            scored_defensive = sorted([s for s in defensive if s in scores], key=lambda s: scores[s], reverse=True)
            if safe_frac > 0 and scored_defensive:
                top_def = scored_defensive[:2]
                def_w = inv_vol_weights(top_def, i)
                for s, w in def_w.items():
                    weights[s] = weights.get(s, 0.0) + w * safe_frac

            if not weights:
                continue

            # Portfolio vol targeting
            port_vol = sum(weights[s] * get_vol(s, i) for s in weights)
            port_vol = max(port_vol, 0.04)
            scale = min(p['vol_target'] / port_vol, p['max_scale'])

            # Macro: only dampen at extreme VIX
            vix = self.macro.get('VIXCLS', date)
            if vix is not None:
                if vix > 45:
                    scale *= 0.5
                elif vix > 35:
                    scale *= 0.75

            total_budget = min(p['total_size'] * scale, p['total_size'])

            for s in weights:
                cur_alloc[s] = weights[s] * total_budget

            for s in syms:
                a = cur_alloc.get(s, 0.0)
                if a > 0.0:
                    sig_arr[s][i] = 1
                    sz_arr[s][i] = a

        return {
            s: pd.DataFrame({'signal': sig_arr[s], 'size_pct': sz_arr[s]}, index=dates)
            for s in syms
        }
",
